import style from "./index.module.scss"
import template from './index.html'

export default class NavItem extends HTMLElement {
  root: HTMLElement
  set name(value: string) {
    this.setAttribute("name", value)
  }
  get name(): string {
    return this.getAttribute("name") || ""
  }
  set description(value: string) {
    this.setAttribute("description", value)
  }
  get description(): string {
    return this.getAttribute("description") || ""
  }
  set open(value: string) {
    this.setAttribute("open", value)
  }
  get open(): boolean {
    const value = this.getAttribute("open")
    return value === "true" ? true : false
  }
  set active(value: string) {
    this.setAttribute("active", value)
  }
  get active(): boolean {
    const value = this.getAttribute("active")
    return value === "true" ? true : false
  }
  set collapse(value: boolean) {
    if (value) {
      this.setAttribute("collapse", value.toString())
    } else {
      this.removeAttribute("collapse")
    }
  }
  get collapse(): boolean {
    const value = this.getAttribute("collapse")
    return value === "true" ? true : false
  }
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return ['open', 'active', 'name', "description", "collapse"];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }

  handleClick = e => {
    const event = new CustomEvent("huanlin-nav-item", {
      bubbles: true,
    });
    e.currentTarget.dispatchEvent(event)
  }
  willLoad = () => {
    this.root = this.shadowRoot?.querySelector(".container") as HTMLElement
    this.addEventListener("click", this.handleClick)
  }
  connectedCallback() {
    this.classList.add("hydrated")
    setTimeout(() => {
      this.willLoad()
      this.render()
    })
  }
  disconnectedCallback() {
    this.removeEventListener("click", this.handleClick)
  }

  render = () => {
  }

  setFocus = () => {
    if (this.root) {
      this.root.focus()
    }
  }
  setBlur = () => {
    if (this.root) {
      this.root.blur()
    }
  }

}

